from graphene import ObjectType, Field, List, String, Int
from flask_graphql import GraphQLView as GraphQLView
from graphene_sqlalchemy import SQLAlchemyObjectType, SQLAlchemyQueryMixin
from flask import Flask
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///products.db'
db = SQLAlchemy(app)

class Product(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(100), nullable=False)
    price = db.Column(db.Float, nullable=False)
    description = db.Column(db.Text, nullable=False)

class Category(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(100), nullable=False)

class Review(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    product_id = db.Column(db.Integer, db.ForeignKey('product.id'), nullable=False)
    user_name = db.Column(db.String(100), nullable=False)
    review_text = db.Column(db.Text, nullable=False)

class ProductSchema(SQLAlchemyObjectType):
    class Meta:
        model = Product
        include_relationships = True

class CategorySchema(SQLAlchemyObjectType):
    class Meta:
        model = Category
        include_relationships = True

class ReviewSchema(SQLAlchemyObjectType):
    class Meta:
        model = Review
        include_relationships = True

class Query(ObjectType):
    products = Field(List(ProductSchema))
    categories = Field(List(CategorySchema))
    product = Field(ProductSchema, id=Int(required=True))
    category = Field(CategorySchema, id=Int(required=True))
    reviews = Field(List(ReviewSchema))
    review = Field(ReviewSchema, id=Int(required=True))

    def resolve_products(self, info):
        return Product.query.all()

    def resolve_categories(self, info):
        return Category.query.all()

    def resolve_product(self, info, id):
        return Product.query.get(id)

    def resolve_category(self, info, id):
        return Category.query.get(id)

    def resolve_reviews(self, info):
        return Review.query.all()

    def resolve_review(self, info, id):
        return Review.query.get(id)

class Mutation(ObjectType):
    pass

schema = graphene.Schema(query=Query)

GraphQLView.as_view('graphql', schema=schema, graphiql=True)(app)

if __name__ == '__main__':
    app.run(debug=True)